import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Grid } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface TaskCounts {
  todo: number;
  inProgress: number;
  done: number;
}

interface KanbanData {
  boardName: string;
  taskCounts: TaskCounts;
  totalTasks: number;
}

export default function Widget() {
  const kanbanData = response.data as KanbanData;
  const { boardName, taskCounts, totalTasks } = kanbanData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: theme === 'light' ? '#FFFFFF' : '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: primaryColor }}>
              {boardName}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total Tasks: {totalTasks}
            </Typography>
          </Box>

          <BarChart
            height={120}
            series={[
              {
                data: [taskCounts.todo, taskCounts.inProgress, taskCounts.done],
                color: accentColor,
              },
            ]}
            xAxis={[
              {
                data: ['To Do', 'In Progress', 'Done'],
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: theme === 'light' ? '#6B7280' : '#D1D5DB',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />

          <Grid container spacing={1}>
            {Object.entries(taskCounts).map(([status, count], index) => (
              <Grid item xs={4} key={index}>
                <Chip
                  label={`${status.charAt(0).toUpperCase() + status.slice(1)}: ${count}`}
                  sx={{ width: '100%', fontSize: '10px', bgcolor: theme === 'light' ? '#F3F4F6' : '#374151', color: '#FFFFFF' }}
                />
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
